import subprocess
import os

def convertDocument(input_file, output_file, format_type):
    # Determine the output format based on the extension
    if format_type.lower() == 'pdf':
        output_format = 'pdf'
    elif format_type.lower() == 'docx':
        output_format = 'docx'
    elif format_type.lower() == 'txt':
        output_format = 'txt'
    elif format_type.lower() in ['jpg', 'jpeg', 'png', 'bmp']:
        output_format = 'pdf'
    else:
        raise ValueError("Unsupported format")
    
    # Build the LibreOffice command
    cmd = [
        'libreoffice',
        '--headless',
        '--convert-to',
        output_format,
        '--outdir',
        os.path.dirname(os.path.abspath(output_file)),
        input_file
    ]
    
    try:
        # Execute the command
        subprocess.run(cmd, check=True)
        
        # If converting to PDF from image, we need to rename the file
        if format_type.lower() in ['jpg', 'jpeg', 'png', 'bmp']:
            # Get the base name without extension
            base_name = os.path.splitext(input_file)[0]
            # The output file will be named with .pdf extension
            temp_output = os.path.join(os.path.dirname(os.path.abspath(output_file)), 
                                     os.path.basename(base_name) + '.pdf')
            # Rename the file if needed
            if os.path.exists(temp_output):
                os.rename(temp_output, output_file)
    except subprocess.CalledProcessError as e:
        raise RuntimeError(f"Conversion failed: {e}")